// src/pages/Leave/LeavePage.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  CalendarDays, Plus, Check, X, Clock, AlertCircle,
  Send, BarChart2, Calendar, Edit3, Users, Settings,
  RefreshCw, ArrowRightLeft, Shield
} from 'lucide-react';
import toast from 'react-hot-toast';
import { leaveAPI, notificationAPI } from '../../api/services';
import { Modal, Badge, SkeletonCard, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';

// ─── SAFE ERROR EXTRACTOR ────────────────────────────────────────────────────
const getErrMsg = (err) => {
  const d = err.response?.data;
  if (d?.error?.message) return d.error.message;
  if (typeof d?.error === 'string') return d.error;
  if (typeof d?.message === 'string') return d.message;
  return err.message || 'An unexpected error occurred';
};

// ─── INLINE MODAL ────────────────────────────────────────────────────────────
const InlineModal = ({ title, onClose, children }) => (
  <div style={{ position: 'fixed', top:0, left:0, right:0, bottom:0, background:'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
    <div className="card" style={{ width: '100%', maxWidth: 500, maxHeight: '90vh', overflowY: 'auto', background: '#fff', borderRadius: 8 }}>
      <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem', borderBottom: '1px solid #eee' }}>
         <div className="card-title" style={{ fontWeight: 600, fontSize: '1.1rem', margin: 0 }}>{title}</div>
         <button className="btn btn-ghost" style={{ padding: 4, background: 'none', border: 'none', cursor: 'pointer' }} onClick={onClose}><X size={18}/></button>
      </div>
      <div style={{ padding: '1rem' }}>
        {children}
      </div>
    </div>
  </div>
);

// ─── STATUS CONSTANTS & HELPERS ──────────────────────────────────────────────
const STATUS_LABEL = {
  SUBMITTED: 'Submitted', PENDING_MANAGER: 'Pending Approval',
  PendingManager: 'Pending Approval', PENDING_HR: 'Pending HR',
  APPROVED: 'Approved', REJECTED: 'Rejected', CANCELLED: 'Cancelled',
  DRAFT: 'Draft', Submitted: 'Submitted', Pending: 'Pending Approval',
  Approved: 'Approved', Rejected: 'Rejected', Cancelled: 'Cancelled',
};

const STATUS_OPTIONS = [
  { value: '', label: 'All' }, { value: 'SUBMITTED', label: 'Submitted' },
  { value: 'PENDING_MANAGER', label: 'Pending Approval' }, { value: 'APPROVED', label: 'Approved' },
  { value: 'REJECTED', label: 'Rejected' }, { value: 'CANCELLED', label: 'Cancelled' },
];

const STATUS_HISTORY = [
  { value: '', label: 'All' }, { value: 'SUBMITTED', label: 'Submitted' },
  { value: 'PENDING_MANAGER', label: 'Pending' }, { value: 'APPROVED', label: 'Approved' },
  { value: 'REJECTED', label: 'Rejected' }, { value: 'CANCELLED', label: 'Cancelled' },
];

const normStatus = s => (s || '').toUpperCase().replace(/_/g, '');
const statusMatches = (reqStatus, filterValue) => {
  if (!filterValue) return true;
  const rs = normStatus(reqStatus);
  const fv = normStatus(filterValue);
  if (rs === fv) return true;
  const allPending = new Set(['PENDINGMANAGER','PENDINGHR','SUBMITTED','PENDING','DRAFT']);
  if (fv === 'PENDINGMANAGER' && allPending.has(rs)) return true;
  return false;
};
const isFinalStatus = s => ['APPROVED','REJECTED','CANCELLED'].includes(normStatus(s));

const toArr = (r) => {
  if (!r) return [];
  const d = r.data?.data || r.data?.requests || r.data || r.requests || r || [];
  return Array.isArray(d) ? d : [];
};

function RequestRow({ req, onAction, onEdit, onOverrideClick, isManager, isHR }) {
  const [acting, setActing] = useState('');

  const leaveTypeName = req.LeaveType?.LeaveTypeName || req.leaveType?.LeaveTypeName || req.LeaveTypeName || req.leaveTypeName || '—';
  const empFullName = req.Employee?.FullName || req.employee?.fullName || req.EmployeeName || req.employeeName || '—';
  const startDate = req.StartDate || req.startDate;
  const endDate = req.EndDate || req.endDate;
  const totalDays = req.TotalDays ?? req.totalDays ?? '—';
  const currentStatus = req.Status || req.status || 'SUBMITTED';
  const leaveReason = req.Reason || req.reason || '—';
  const id = req.LeaveRequestID || req.id;

  const from = startDate ? new Date(startDate).toLocaleDateString() : '—';
  const to = endDate ? new Date(endDate).toLocaleDateString() : '—';

  const act = async (action) => {
    setActing(action);
    try { await onAction(id, action); } finally { setActing(''); }
  };

  const isFinal = isFinalStatus(currentStatus);

  return (
    <tr>
      <td>
        <div style={{ fontWeight: 500 }}>{leaveTypeName}</div>
        {!isManager && leaveReason !== '—' && <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: 2 }}>{leaveReason}</div>}
      </td>
      {isManager && <td><div style={{ fontWeight: 500 }}>{empFullName}</div></td>}
      <td style={{ fontSize: '0.82rem' }}>{from} → {to}</td>
      <td>{totalDays}</td>
      <td>
        <span style={{
          display: 'inline-block', padding: '3px 10px', borderRadius: 20, fontSize: '0.75rem', fontWeight: 600,
          background: normStatus(currentStatus) === 'APPROVED' ? 'rgba(34,197,94,0.15)' : normStatus(currentStatus) === 'REJECTED' ? 'rgba(239,68,68,0.15)' : 'rgba(251,191,36,0.15)',
          color: normStatus(currentStatus) === 'APPROVED' ? '#16a34a' : normStatus(currentStatus) === 'REJECTED' ? '#dc2626' : '#b45309',
        }}>{STATUS_LABEL[currentStatus] || currentStatus}</span>
      </td>
      {isManager && (
        <td style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', maxWidth: 160 }}>
          {leaveReason.slice(0, 60)}{leaveReason.length > 60 ? '…' : ''}
        </td>
      )}
      <td>
        <div style={{ display: 'flex', gap: 6 }}>
          {/* RULE: Only Supervisors/Managers can Approve/Reject. HR CANNOT. */}
          {isManager && !isHR && !isFinal && (
            <>
              <button className="btn btn-success btn-sm" onClick={() => act('approve')} disabled={!!acting}>{acting === 'approve' ? <InlineSpinner /> : 'Approve'}</button>
              <button className="btn btn-danger btn-sm" onClick={() => act('reject')} disabled={!!acting}>{acting === 'reject' ? <InlineSpinner /> : 'Reject'}</button>
            </>
          )}
          {/* RULE: Only HR can Override finalized items. Managers CANNOT. */}
          {isHR && isFinal && normStatus(currentStatus) !== 'CANCELLED' && onOverrideClick && (
            <button className="btn btn-ghost btn-sm" onClick={() => onOverrideClick(req)} disabled={!!acting}><Shield size={13} style={{marginRight: 4}}/> Override</button>
          )}
          {!isManager && !isFinal && (
            <button className="btn btn-ghost btn-sm" onClick={() => act('cancel')} disabled={!!acting}>Cancel</button>
          )}
        </div>
      </td>
    </tr>
  );
}

function BalanceCard({ balance, loading }) {
  if (loading) return <SkeletonCard />;
  const name = balance.leaveTypeName || balance.LeaveTypeName || balance.LeaveType?.LeaveTypeName || 'Leave';
  const used = Number(balance.usedDays ?? balance.UsedDays ?? 0);
  const remaining = Number(balance.remainingDays ?? balance.RemainingDays ?? 0);
  const maxDays = Number(balance.maxDaysPerYear ?? (used + remaining));
  const pct = maxDays > 0 ? Math.round((remaining / maxDays) * 100) : 0;
  const color = name.includes('Sick') ? 'var(--green)' : 'var(--blue)';

  return (
    <div className="stat-card">
      <div className="stat-card-accent" style={{ background: color }} />
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12 }}>
        <div style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', fontWeight: 500, textTransform: 'uppercase' }}>{name}</div>
        <CalendarDays size={18} style={{ color }} />
      </div>
      <div className="stat-card-value" style={{ color }}>{remaining}</div>
      <div className="stat-card-label">days remaining of {maxDays}</div>
      <div className="stat-card-progress" style={{ marginTop: 12 }}><div className="stat-card-progress-bar" style={{ width: `${pct}%`, background: color }} /></div>
    </div>
  );
}

function DelegationPanel({ onDelegate, employees }) {
  const [delegateTo, setDelegateTo] = useState('');
  const [until, setUntil] = useState('');

  const handleActivate = () => {
    onDelegate(1, { 
      delegateId: parseInt(delegateTo, 10),
      startDate: new Date().toISOString(),
      endDate: new Date(until).toISOString(),
      comments: `Delegated until ${until}`
    });
  };

  return (
    <div className="card" style={{ marginBottom: 16 }}>
      <div className="card-header"><div className="card-title"><Users size={15} style={{ marginRight: 6 }} />Approval Delegation</div></div>
      <div className="form-row">
        <div className="form-group">
          <label className="form-label">Delegate To</label>
          {employees && employees.length > 0 ? (
            <select className="form-select" value={delegateTo} onChange={e => setDelegateTo(e.target.value)}>
              <option value="">— Select Employee —</option>
              {employees.map(emp => (
                <option key={emp.id} value={emp.id}>{emp.name}</option>
              ))}
            </select>
          ) : (
            <input className="form-input" type="number" value={delegateTo} onChange={e => setDelegateTo(e.target.value)} placeholder="Employee ID" />
          )}
        </div>
        <div className="form-group"><label className="form-label">Delegate Until</label><input className="form-input" type="date" value={until} onChange={e => setUntil(e.target.value)} /></div>
      </div>
      <button className="btn btn-primary btn-sm" disabled={!delegateTo || !until} onClick={handleActivate}>Activate Delegation</button>
    </div>
  );
}

function SubmitLeaveForm({ leaveTypes, onSubmit, loading }) {
  const [form, setForm] = useState({ LeaveTypeID: '', startDate: '', endDate: '', reason: '', isHalfDay: false });
  const handle = () => {
    if (!form.LeaveTypeID || !form.startDate || !form.endDate) return toast.error("Required fields missing");
    onSubmit({ ...form, LeaveTypeID: parseInt(form.LeaveTypeID, 10) });
  };
  return (
    <>
      <div className="form-group"><label className="form-label required">Leave Type</label>
        <select className="form-select" value={form.LeaveTypeID} onChange={e => setForm({...form, LeaveTypeID: e.target.value})}>
          <option value="">— Select —</option>
          {leaveTypes.map(t => <option key={t.LeaveTypeID} value={t.LeaveTypeID}>{t.LeaveTypeName}</option>)}
        </select>
      </div>
      <div className="form-row">
        <div className="form-group"><label className="form-label required">Start</label><input className="form-input" type="date" onChange={e => setForm({...form, startDate: e.target.value})} /></div>
        <div className="form-group"><label className="form-label required">End</label><input className="form-input" type="date" onChange={e => setForm({...form, endDate: e.target.value})} /></div>
      </div>
      <div className="form-group"><label className="form-label">Reason</label><textarea className="form-textarea" rows={2} onChange={e => setForm({...form, reason: e.target.value})} /></div>
      <button className="btn btn-primary w-full" onClick={handle} disabled={loading}>{loading ? <InlineSpinner /> : 'Submit'}</button>
    </>
  );
}

export default function LeavePage() {
  const { user } = useAuth();
  const posId = parseInt(user?.PositionID || user?.positionId, 10);
  const roleStr = (user?.role || user?.Role || '').toUpperCase();
  const userEmail = (user?.email || user?.Email || '').toLowerCase();

  const isManager = roleStr.includes('MANAGER') || roleStr.includes('ADMIN') || roleStr.includes('PROFESSOR') || posId === 1 || posId === 2 || userEmail === 'mona@university.edu';
  const isHR = roleStr.includes('HR') || roleStr.includes('ADMIN') || posId === 1;

  // RULE: Only non-HR Managers (Professors/Supervisors) and HR Managers (Position 1) can delegate.
  const canDelegate = (isManager && !isHR) || posId === 1;

  const [tab, setTab] = useState('dashboard');
  const [balances, setBalances] = useState([]);
  const [myRequests, setMyReqs] = useState([]);
  const [allRequests, setAll] = useState([]);
  const [leaveTypes, setTypes] = useState([]);
  const [loadBal, setLoadBal] = useState(true);
  const [loadReq, setLoadReq] = useState(true);
  const [loadAll, setLoadAll] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [historyFilter, setHistoryFilter] = useState('');
  const [allFilter, setAllFilter] = useState('');
  const [reasonModal, setReasonModal] = useState(null); 
  const [overrideReq, setOverrideReq] = useState(null); 
  const [actingReason, setActingReason] = useState(false);
  const [editingRequest, setEditingRequest] = useState(null);
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);

  const loadData = useCallback(() => {
    setLoadBal(true); setLoadReq(true);
    leaveAPI.getMyBalances().then(r => setBalances(toArr(r))).finally(() => setLoadBal(false));
    leaveAPI.getMyRequests().then(r => setMyReqs(toArr(r))).finally(() => setLoadReq(false));
    leaveAPI.getTypes().then(r => setTypes(toArr(r)));
    if (isManager) {
      setLoadAll(true);
      const fetchMethod = isHR ? leaveAPI.listAll() : leaveAPI.getManagerInbox();
      fetchMethod.then(r => setAll(toArr(r))).finally(() => setLoadAll(false));
    }
  }, [isManager, isHR]);

  useEffect(() => { loadData(); }, [loadData]);

  const uniqueEmployees = Array.from(new Map(allRequests.filter(r => r.EmployeeID || r.employeeId).map(r => [r.EmployeeID || r.employeeId, r.Employee?.FullName || r.employeeName])).entries()).map(([id, name]) => ({ id, name }));

  const handleSubmit = async (p) => {
    setSubmitting(true);
    try { await leaveAPI.submit(p); toast.success('Submitted!'); setIsSubmitModalOpen(false); loadData(); } catch (err) { toast.error(getErrMsg(err)); } finally { setSubmitting(false); }
  };

  const handleAction = async (id, action, reason) => {
    try {
      if (action === 'approve') await leaveAPI.approveReject(id, { decision: 'APPROVED' });
      else if (action === 'reject') await leaveAPI.approveReject(id, { decision: 'REJECTED', comments: reason });
      else if (action === 'cancel') await leaveAPI.cancel(id, { CancelReason: reason });
      toast.success('Updated!'); loadData();
    } catch (err) { toast.error(getErrMsg(err)); }
  };

  const handleOverride = async (id, status, reason) => {
    setActingReason(true);
    try { await leaveAPI.approveReject(id, { decision: status, comments: reason }); toast.success('Overridden!'); setOverrideReq(null); loadData(); } catch (err) { toast.error(getErrMsg(err)); } finally { setActingReason(false); }
  };

  const handleDelegate = async (id, p) => { try { await leaveAPI.delegate(id, p); toast.success("Delegated."); } catch(err) { toast.error(getErrMsg(err)); } };

  const TABS = [
    { id: 'dashboard', label: 'Dashboard', icon: BarChart2 },
    { id: 'history', label: 'My History', icon: Clock },
    ...(isManager ? [{ id: 'all', label: isHR ? 'Company Requests' : 'Team Inbox', icon: Users }] : []),
    ...(isHR ? [{ id: 'settings', label: 'Settings', icon: Settings }] : []),
  ];

  return (
    <>
      {reasonModal && <ReasonModal title="Reject Request" onConfirm={(r) => handleAction(reasonModal.id, 'reject', r)} onClose={() => setReasonModal(null)} loading={actingReason} />}
      {overrideReq && <OverrideModal req={overrideReq} onConfirm={handleOverride} onClose={() => setOverrideReq(null)} loading={actingReason} />}
      {isSubmitModalOpen && <InlineModal title="Request Leave" onClose={() => setIsSubmitModalOpen(false)}><SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleSubmit} loading={submitting} /></InlineModal>}

      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem' }}>
        <div><h1>Leave Management</h1><p>Manage requests and approvals</p></div>
        <button className="btn btn-primary" onClick={() => setIsSubmitModalOpen(true)}><Plus size={18} /> New Request</button>
      </div>

      <div className="tabs" style={{ padding: '0 1rem' }}>
        {TABS.map(({ id, label, icon: Icon }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}><Icon size={14} style={{ marginRight: 6 }} />{label}</button>
        ))}
      </div>

      <div style={{ padding: '1rem' }}>
        {tab === 'dashboard' && <div className="grid-4">{balances.map((b, i) => <BalanceCard key={i} balance={b} loading={loadBal} />)}</div>}

        {tab === 'history' && (
          <div className="card">
            <div className="table-wrap">
              <table>
                <thead><tr><th>Type</th><th>Period</th><th>Days</th><th>Status</th><th>Actions</th></tr></thead>
                <tbody>{myRequests.filter(r => statusMatches(r.Status, historyFilter)).map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} isManager={false} />)}</tbody>
              </table>
            </div>
          </div>
        )}

        {tab === 'all' && isManager && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            {canDelegate && <DelegationPanel onDelegate={handleDelegate} employees={uniqueEmployees} />}
            <div className="card">
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Type</th><th>Employee</th><th>Period</th><th>Days</th><th>Status</th><th>Reason</th><th>Actions</th></tr></thead>
                  <tbody>{allRequests.filter(r => statusMatches(r.Status, allFilter)).map((req, i) => <RequestRow key={i} req={req} onAction={(id, act) => act === 'reject' ? setReasonModal({id}) : handleAction(id, act)} onOverrideClick={setOverrideReq} isManager={true} isHR={isHR} />)}</tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </div>
    </>
  );
}
